  ('fb2477db-1618-4263-b64b-bdd2024228ba', 'Er ist gestern gekommen.', 'He came yesterday.', 'لقد أمس أتى.', 'Used in Kultur und Gesellschaft', 'neutral', false, NULL, 7),
