  ('672b5335-1fdb-4281-af03-84120b01baa6', 'Kannst du mir helfen?', 'Can you help me?', 'هل يمكنك مساعدتي؟', 'Used in Fachsprache und Terminologie', 'informal', false, NULL, 5),
  ('672b5335-1fdb-4281-af03-84120b01baa6', 'Wir müssen jetzt gehen.', 'We must go now.', 'يجب أن نذهب الآن.', 'Used in Fachsprache und Terminologie', 'neutral', false, NULL, 6),
  ('672b5335-1fdb-4281-af03-84120b01baa6', 'Er ist gestern gekommen.', 'He came yesterday.', 'لقد أمس أتى.', 'Used in Fachsprache und Terminologie', 'neutral', false, NULL, 7),
