  ('5825abf1-9f6f-40a0-a86d-4f69fd8c54ea', 'Mein Büro ist im Zentrum.', 'My office is in the center.', 'مكتبي في المركز.', 'Used in Berufliche Kommunikation', 'neutral', false, NULL, 6),
